// Normalize incoming appointment payload from GHL
const appt = items[0].json;
return [{
  json: {
    contact_id: appt.contact_id || 'DEMO-CONTACT-ID',
    appointment_id: appt.appointment_id || 'DEMO-APPT-ID',
    start_time: appt.start_time || new Date().toISOString(),
    service: appt.service || 'Consultation'
  }
}];
